mapper.select:
SELECT ROWNUM AS ROW_NUM ,GETUSERNAME(NOTC.GATE_CD, NOTC.REG_USER_ID , #{ses.langCd}) AS REG_USER_NAME ,(CASE WHEN GETFILECOUNT(NOTC.GATE_CD, NOTC.ATT_FILE_NUM) = 0 THEN NULL ELSE GETFILECOUNT(NOTC.GATE_CD, NOTC.ATT_FILE_NUM) END) AS ATTACH_FILE_NO_DISPLAY ,(NOTC.REG_DATE, 'YYYY-MM-DD') AS REG_DATE ,(NOTC.START_DATE, 'YYYY-MM-DD') ' ~ ' (NOTC.END_DATE, 'YYYY-MM-DD') AS NOTICE_DATE , NOTC.VIEW_TYPE , NOTC.SUBJECT , NOTC.REG_USER_ID AS REG_USER_ID , NOTC.ATT_FILE_NUM AS ATTACH_FILE_NO ,(CASE WHEN NOTC.ATT_FILE_NUM IS NOT NULL AND (SELECT COUNT(*) FROM STOCATCH WHERE GATE_CD = #{ses.gateCd} AND UUID = NOTC.ATT_FILE_NUM AND DEL_FLAG = '0') > 0 THEN '0' ELSE '1' END) AS ATTACH_FILE_NO_DISPLAY_IMAGE ,(NOTC.VIEW_CNT, 0) AS VIEW_CNT , NOTC.GATE_CD , NOTC.NOTICE_NUM ,(NOTC.POPUP_FLAG, '0') AS POPUP_FLAG , NOTC.FIXED_TOP_FLAG , COMMENT1 , COMMENT2 FROM STOCNOTC NOTC WHERE NOTC.GATE_CD = #{ses.gateCd} AND NOTC.NOTICE_TYPE = #{NOTICE_TYPE} AND NOTC.DEL_FLAG = '0'
AND ((NOTC.START_DATE >= #{ADD_FROM_DATE} AND NOTC.START_DATE <= #{ADD_TO_DATE}) OR (NOTC.END_DATE >= #{ADD_FROM_DATE} AND NOTC.END_DATE <= #{ADD_TO_DATE}))
AND NOTC.START_DATE >= #{ADD_FROM_DATE}
AND NOTC.END_DATE <= #{ADD_TO_DATE}
AND NOTC.VIEW_TYPE = #{VIEW_TYPE}
AND UPPER(GETUSERNAME(NOTC.GATE_CD, NOTC.REG_USER_ID, #{ses.langCd})) LIKE '%' UPPER(#{ADD_USER_NAME}) '%'
AND UPPER(NOTC.SUBJECT) like '%' UPPER(#{SUBJECT}) '%'
ORDER BY NOTC.FIXED_TOP_FLAG DESC, NOTC.REG_DATE DESC, NOTC.NOTICE_NUM DESC

mapper.update:
UPDATE STOCNOTC SET
       VIEW_CNT   = #{VIEW_CNT}
 WHERE GATE_CD    = #{ses.gateCd}
   AND NOTICE_NUM = #{NOTICE_NUM}

mapper.insert:
INSERT INTO STOCNOTC (
      GATE_CD
    , BUYER_CD
    , DEPT_CD
    , NOTICE_NUM
    , REG_DATE
    , REG_USER_ID
    , MOD_DATE
    , MOD_USER_ID
    , DEL_FLAG
    , POPUP_FLAG	-- ASP계약 및 동의서에서 임시저장(0), 완료(1)로 사용
    , SUBJECT
    , NOTICE_TYPE
    , VIEW_TYPE
    , FIXED_TOP_FLAG
    , START_DATE
    , END_DATE
    , NOTICE_TEXT_NUM
    , ATT_FILE_NUM
    , VIEW_CNT
    , COMMENT1
    , COMMENT2
) VALUES (
      #{ses.gateCd}
    , #{ses.companyCd}
    , #{ses.deptCd}
    , #{NOTICE_NUM}
    , SYSDATE
    , #{ses.userId}
    , SYSDATE
    , #{ses.userId}
    , '0'
    , (#{POPUP_FLAG}, '0')		-- ASP계약 및 동의서에서 임시저장(0), 완료(1)로 사용
    , #{SUBJECT}
    , #{NOTICE_TYPE}
    , #{VIEW_TYPE}
    , CASE WHEN (#{FIXED_TOP_FLAG}, '0' ) = 'on' THEN '1' ELSE '0' END
    , #{START_DATE}
    , #{END_DATE}
    , #{NOTICE_TEXT_NUM}
    , #{ATT_FILE_NUM}
    , 0
    , #{COMMENT1}
    , #{COMMENT2}
)

mapper.update:
UPDATE STOCNOTC SET
      MOD_DATE        = SYSDATE
    , MOD_USER_ID     = #{ses.userId}
    , POPUP_FLAG      = (#{POPUP_FLAG}, '0')	-- ASP계약 및 동의서에서 임시저장(0), 완료(1)로 사용
    , SUBJECT         = #{SUBJECT}
    , VIEW_TYPE       = #{VIEW_TYPE}
    , FIXED_TOP_FLAG  = CASE WHEN (#{FIXED_TOP_FLAG}, '0' ) = 'on' THEN '1' ELSE '0' END
    , START_DATE      = #{START_DATE}
    , END_DATE        = #{END_DATE}
    , NOTICE_TEXT_NUM = #{NOTICE_TEXT_NUM}
    , ATT_FILE_NUM    = #{ATT_FILE_NUM}
    , COMMENT1        = #{COMMENT1}
    , COMMENT2        = #{COMMENT2}
WHERE GATE_CD    = #{ses.gateCd}
  AND NOTICE_NUM = #{NOTICE_NUM}

UPDATE STOCNOTC SET
      DEL_FLAG = '1'
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD    = #{ses.gateCd}
  AND NOTICE_NUM = #{NOTICE_NUM}

UPDATE STOCNOTC SET
       FIXED_TOP_FLAG = CASE WHEN (#{FIXED_TOP_FLAG}, '0' ) = 'on' THEN '0' ELSE FIXED_TOP_FLAG END
 WHERE GATE_CD     = #{ses.gateCd}
   AND NOTICE_TYPE = #{NOTICE_TYPE}
   AND VIEW_TYPE   = #{VIEW_TYPE}
   AND FIXED_TOP_FLAG = '1'	-- 최종여부

mapper.select:
SELECT CMSV.COMPANY_CD , CMSV.USER_TYPE , CMSV.SIGN_ID , CMSV.SIGN_SQ ,GETUSERNAME(CMSV.GATE_CD, CMSV.SIGN_ID, #{ses.langCd}) AS SIGN_USER_NM , CMSV.PROGRESS_CD ,(CASE WHEN CMSV.USER_TYPE = 'B' THEN (SELECT CUST_NM FROM STOCCUST WHERE GATE_CD = CMSV.GATE_CD AND CUST_CD = CMSV.COMPANY_CD) ELSE (SELECT VENDOR_NM FROM STOCVNGL WHERE GATE_CD = CMSV.GATE_CD AND VENDOR_NM = CMSV.COMPANY_CD) END) AS COMPANY_NM ,GETDEPTNAME(CMSV.GATE_CD, CMSV.COMPANY_CD, (SELECT NVL(CODE,'') FROM STOCCODD WHERE CODE_TYPE = 'M406' AND TEXT2 = CMSV.FORM_NUM), #{ses.langCd}) AS SIGN_DEPT_NM ,(CMSV.SIGN_DATE, 'YYYY-MM-DD HH24:MI:SS') AS SIGN_DATE , NOTC.VIEW_TYPE , NOTC.SUBJECT , NOTC.NOTICE_NUM , CMSV.CONT_START_DATE , CMSV.CONT_END_DATE , SUBSTR(CMSV.VENDOR_IRS_NUM, 0, 3)'-' SUBSTR(CMSV.VENDOR_IRS_NUM, 4, 2)'-' SUBSTR(CMSV.VENDOR_IRS_NUM, 6) AS VENDOR_IRS_NUM , CMSV.VENDOR_NM ,CMSV.VENDOR_CEO_NM AS VENDOR_CEO_NM FROM STOCCMSV CMSV JOIN STOCNOTC NOTC ON (CMSV.GATE_CD = NOTC.GATE_CD AND CMSV.FORM_NUM = NOTC.NOTICE_NUM AND NOTC.NOTICE_TYPE = 'CMS') WHERE CMSV.GATE_CD = #{ses.gateCd}
AND ((CMSV.CONT_START_DATE >= #{ADD_FROM_DATE} AND CMSV.CONT_START_DATE <= #{ADD_TO_DATE}) OR (CMSV.CONT_END_DATE >= #{ADD_FROM_DATE} AND CMSV.CONT_END_DATE <= #{ADD_TO_DATE}))
AND CMSV.CONT_START_DATE >= #{ADD_FROM_DATE}
AND CMSV.CONT_END_DATE <= #{ADD_TO_DATE}
AND NOTC.VIEW_TYPE = #{VIEW_TYPE}
AND UPPER(CMSV.VENDOR_NM) like '%' UPPER(#{SUBJECT}) '%'
ORDER BY CMSV.REG_DATE DESC
